// ── v8 FIX: try numFound FIRST (dealer CDK/DealerSocket APIs use numFound for total inventory,
// totalCount is often the per-page count). Fallback chain covers all known dealer API shapes.
const resp = $input.item.json;
const pageInfo = resp?.pageInfo || {};

const totalCount =
  pageInfo.numFound          ||
  pageInfo.totalCount        ||
  pageInfo.total             ||
  pageInfo.numRecords        ||
  pageInfo.totalItems        ||
  pageInfo.count             ||
  pageInfo.recordsTotal      ||
  pageInfo.filteredCount     ||
  resp?.numFound             ||
  resp?.totalCount           ||
  resp?.total                ||
  0;

if (!resp || resp.error) {
  throw new Error('USED API error: ' + JSON.stringify(resp).substring(0, 300));
}
if (totalCount < 1) {
  throw new Error(
    'USED totalCount is zero or missing. pageInfo was: ' +
    JSON.stringify(pageInfo).substring(0, 500) +
    ' | full response keys: ' + Object.keys(resp).join(', ')
  );
}

return { json: { totalCount, sync_started_at: $('Capture Sync Start').first().json.sync_started_at } };

const resp = $input.item.json;
if (!resp || resp.error || !resp.pageInfo) { throw new Error('sbmercedes NEW API bad response: ' + JSON.stringify(resp).substring(0, 200)); }
const totalCount = resp.pageInfo.totalCount;
if (!totalCount || totalCount < 1) { throw new Error('NEW totalCount missing or zero'); }
return { json: { totalCount, sync_started_at: $('Capture Sync Start').item.json.sync_started_at } };

const totalCount = $input.item.json.totalCount;
const syncStart = $input.item.json.sync_started_at;
const pageSize = 100;
const totalPages = Math.ceil(totalCount / pageSize);
const pages = [];
for (let i = 0; i < totalPages; i++) {
  pages.push({ json: {
    pageStart: i * pageSize,
    pageSize,
    totalCount,
    totalPages,
    pageNumber: i + 1,
    sync_started_at: syncStart
  }});
}
return pages;

const rawData = $input.first().json;
const inventory = rawData.inventory || [];

const trackingMap = {};
const trackingData = rawData.pageInfo?.trackingData || [];
for (const t of trackingData) {
  if (t.vin) trackingMap[t.vin] = t;
}

const seenThisPage = new Set();
const now = new Date().toISOString();
const results = [];

for (const v of inventory) {
  if (!v.vin || seenThisPage.has(v.vin)) continue;
  seenThisPage.add(v.vin);

  const t = trackingMap[v.vin] || {};
  const attrs = {};
  (v.attributes || []).forEach(a => { if (a.name) attrs[a.name] = a.value || ''; });
  const hAttrs = {};
  (v.highlightedAttributes || []).forEach(a => { if (a.name) hAttrs[a.name] = a.value || ''; });

  const msrpNumeric = parseFloat(String(t.msrp || '').replace(/[^0-9.]/g, '')) || 0;
  const salePriceNumeric = parseFloat(t.salePrice) || 0;
  const internetPriceNumeric = parseFloat(t.internetPrice) || 0;
  const msrpFormatted = msrpNumeric ? `$${msrpNumeric.toLocaleString()}` : '';
  const salePriceFormatted = salePriceNumeric ? `$${salePriceNumeric.toLocaleString()}` : '';

  const images = v.images || [];
  const image_url = images[0]?.uri || '';
  const images_json = images.length ? JSON.stringify(images.map(i => i.uri)) : null;

  const exterior_color = t.exteriorColor || attrs.exteriorColor || '';
  const interior_color = t.interiorColor || attrs.interiorColor || '';
  const status = t.status || 'live';
  const is_new = (t.newOrUsed || t.inventoryType || v.condition || 'new').toLowerCase() === 'new';
  const is_certified = !!(t.certified || v.certified);
  const vehicle_url = t.link ? `https://www.sbmercedes.com${t.link}` : '';
  const mileage = t.odometer ? parseInt(t.odometer) : null;

  const priceText = salePriceNumeric && salePriceNumeric < msrpNumeric
    ? `MSRP is ${msrpFormatted}, currently on sale for ${salePriceFormatted}`
    : `MSRP is ${msrpFormatted}`;

  const ai_summary = [
    `${t.year || v.year} Mercedes-Benz ${t.model || v.model || ''} ${attrs.trim || t.trim || ''}`.trim(),
    `${is_certified ? 'Certified Pre-Owned' : is_new ? 'Brand new' : 'Pre-owned'} ${t.bodyStyle || attrs.bodyStyle || ''}`,
    exterior_color ? `Exterior: ${exterior_color}` : null,
    interior_color ? `Interior: ${interior_color}` : null,
    t.transmission ? `Transmission: ${t.transmission === 'A/T' ? 'Automatic' : t.transmission}` : null,
    t.driveLine ? `Drivetrain: ${t.driveLine}` : null,
    t.engine ? `Engine: ${t.engineSize || ''} ${t.engine}`.trim() : null,
    mileage ? `Mileage: ${mileage.toLocaleString()} miles` : null,
    priceText,
    status !== 'live' ? `Status: ${status}` : 'Status: Available',
  ].filter(Boolean).join('. ');

  results.push({ json: {
    vin: v.vin,
    uuid: t.uuid || '',
    stock_number: t.stockNumber || attrs.stockNumber || '',
    year: t.year || v.year || null,
    make: t.make || v.make || 'Mercedes-Benz',
    model: t.model || v.model || '',
    trim: t.trim || attrs.trim || '',
    body_style: t.bodyStyle || attrs.bodyStyle || '',
    exterior_color, interior_color,
    fuel_type: t.normalFuelType || hAttrs.normalFuelType || '',
    transmission: t.transmission || '',
    drivetrain: t.driveLine || '',
    engine: t.engineSize ? `${t.engineSize} ${t.engine || ''}`.trim() : (t.engine || ''),
    doors: t.doors || '',
    msrp: msrpFormatted, msrp_numeric: msrpNumeric,
    sale_price: salePriceNumeric || null,
    internet_price: internetPriceNumeric || null,
    condition: is_new ? 'New' : 'Used',
    is_new, is_certified, status, mileage,
    image_url, images_json, vehicle_url,
    inventory_date: t.inventoryDate || '',
    ai_summary, updated_at: now
  }});
}

if (results.length === 0) return [{ json: { _skipped: true } }];
return results;

const items = $input.all();
const processed = items.filter(i => !i.json._skipped).length;
return [{ json: { loop_signal: true, items_processed: processed } }];

const totalCount = $input.item.json.totalCount;
const syncStart = $input.item.json.sync_started_at;
const pageSize = 100;
const totalPages = Math.ceil(totalCount / pageSize);
const pages = [];
for (let i = 0; i < totalPages; i++) {
  pages.push({ json: {
    pageStart: i * pageSize,
    pageSize,
    totalCount,
    totalPages,
    pageNumber: i + 1,
    sync_started_at: syncStart
  }});
}
return pages;

// ── v8 FIX: default condition changed from 'new' to 'used'.
// The v7 copy-paste from the NEW pipeline used || 'new' as fallback,
// silently tagging all USED vehicles with missing condition as is_new=true.
const rawData = $input.first().json;
const inventory = rawData.inventory || [];

const trackingMap = {};
const trackingData = rawData.pageInfo?.trackingData || [];
for (const t of trackingData) {
  if (t.vin) trackingMap[t.vin] = t;
}

const seenThisPage = new Set();
const now = new Date().toISOString();
const results = [];

for (const v of inventory) {
  if (!v.vin || seenThisPage.has(v.vin)) continue;
  seenThisPage.add(v.vin);

  const t = trackingMap[v.vin] || {};
  const attrs = {};
  (v.attributes || []).forEach(a => { if (a.name) attrs[a.name] = a.value || ''; });
  const hAttrs = {};
  (v.highlightedAttributes || []).forEach(a => { if (a.name) hAttrs[a.name] = a.value || ''; });

  const msrpNumeric = parseFloat(String(t.msrp || '').replace(/[^0-9.]/g, '')) || 0;
  const salePriceNumeric = parseFloat(t.salePrice) || 0;
  const internetPriceNumeric = parseFloat(t.internetPrice) || 0;
  const msrpFormatted = msrpNumeric ? `$${msrpNumeric.toLocaleString()}` : '';
  const salePriceFormatted = salePriceNumeric ? `$${salePriceNumeric.toLocaleString()}` : '';

  const images = v.images || [];
  const image_url = images[0]?.uri || '';
  const images_json = images.length ? JSON.stringify(images.map(i => i.uri)) : null;

  const exterior_color = t.exteriorColor || attrs.exteriorColor || '';
  const interior_color = t.interiorColor || attrs.interiorColor || '';
  const status = t.status || 'live';
  // v8 FIX: fallback is 'used' not 'new' — this pipeline only processes USED inventory
  const is_new = (t.newOrUsed || t.inventoryType || v.condition || 'used').toLowerCase() === 'new';
  const is_certified = !!(t.certified || v.certified);
  const vehicle_url = t.link ? `https://www.sbmercedes.com${t.link}` : '';
  const mileage = t.odometer ? parseInt(t.odometer) : null;

  const priceText = salePriceNumeric && salePriceNumeric < msrpNumeric
    ? `MSRP is ${msrpFormatted}, currently on sale for ${salePriceFormatted}`
